require('dotenv').config();
const { Telegraf, Markup } = require('telegraf');
const Database = require('better-sqlite3');
const path = require('path');

const BOT_TOKEN = process.env.BOT_TOKEN;
if (!BOT_TOKEN) throw new Error('BOT_TOKEN is required');

const bot = new Telegraf(BOT_TOKEN);
const db = new Database(path.join(__dirname, 'astralis.db'));

// ─── DB SETUP ────────────────────────────────────────────────────────────────
db.exec(`
  CREATE TABLE IF NOT EXISTS characters (
    user_id       INTEGER PRIMARY KEY,
    username      TEXT,
    class         TEXT,
    level         INTEGER DEFAULT 1,
    xp            INTEGER DEFAULT 0,
    hp            INTEGER DEFAULT 100,
    max_hp        INTEGER DEFAULT 100,
    attack        INTEGER DEFAULT 10,
    defense       INTEGER DEFAULT 5,
    magic         INTEGER DEFAULT 5,
    speed         INTEGER DEFAULT 10,
    crit          INTEGER DEFAULT 5,
    equipped      TEXT DEFAULT NULL,
    guild_id      INTEGER DEFAULT NULL,
    pvp_wins      INTEGER DEFAULT 0,
    pvp_losses    INTEGER DEFAULT 0,
    pvp_streak    INTEGER DEFAULT 0,
    injured       INTEGER DEFAULT 0,
    daily_quests  TEXT DEFAULT NULL,
    daily_date    TEXT DEFAULT NULL,
    magic_balance INTEGER DEFAULT 0,
    created_at    DATETIME DEFAULT CURRENT_TIMESTAMP
  );

  CREATE TABLE IF NOT EXISTS missions (
    id          INTEGER PRIMARY KEY AUTOINCREMENT,
    user_id     INTEGER,
    difficulty  TEXT,
    started_at  DATETIME,
    ends_at     DATETIME,
    collected   INTEGER DEFAULT 0
  );

  CREATE TABLE IF NOT EXISTS inventory (
    id          INTEGER PRIMARY KEY AUTOINCREMENT,
    user_id     INTEGER,
    item_name   TEXT,
    rarity      TEXT,
    stat_type   TEXT,
    stat_value  INTEGER,
    emoji       TEXT,
    level       INTEGER DEFAULT 1,
    for_sale    INTEGER DEFAULT 0,
    price       INTEGER DEFAULT 0,
    obtained_at DATETIME DEFAULT CURRENT_TIMESTAMP
  );

  CREATE TABLE IF NOT EXISTS burns (
    id          INTEGER PRIMARY KEY AUTOINCREMENT,
    user_id     INTEGER,
    amount      INTEGER DEFAULT 100000,
    mission_id  INTEGER,
    burned_at   DATETIME DEFAULT CURRENT_TIMESTAMP
  );

  CREATE TABLE IF NOT EXISTS guilds (
    id          INTEGER PRIMARY KEY AUTOINCREMENT,
    name        TEXT UNIQUE,
    leader_id   INTEGER,
    description TEXT DEFAULT '',
    level       INTEGER DEFAULT 1,
    xp          INTEGER DEFAULT 0,
    raid_boss   TEXT DEFAULT NULL,
    raid_hp     INTEGER DEFAULT 0,
    raid_max_hp INTEGER DEFAULT 0,
    raid_ends_at DATETIME DEFAULT NULL,
    created_at  DATETIME DEFAULT CURRENT_TIMESTAMP
  );

  CREATE TABLE IF NOT EXISTS pvp_log (
    id           INTEGER PRIMARY KEY AUTOINCREMENT,
    attacker_id  INTEGER,
    defender_id  INTEGER,
    winner_id    INTEGER,
    magic_won    INTEGER DEFAULT 0,
    fought_at    DATETIME DEFAULT CURRENT_TIMESTAMP
  );

  CREATE TABLE IF NOT EXISTS market (
    id          INTEGER PRIMARY KEY AUTOINCREMENT,
    seller_id   INTEGER,
    item_id     INTEGER,
    price       INTEGER,
    listed_at   DATETIME DEFAULT CURRENT_TIMESTAMP
  );

  CREATE TABLE IF NOT EXISTS quest_completions (
    id          INTEGER PRIMARY KEY AUTOINCREMENT,
    user_id     INTEGER,
    quest_key   TEXT,
    completed_at DATETIME DEFAULT CURRENT_TIMESTAMP
  );
`);

