// ─── HELPERS ─────────────────────────────────────────────────────────────────
function xpForLevel(level) { return Math.floor(100 * Math.pow(1.4, level - 1)); }
function getChar(userId) { return db.prepare('SELECT * FROM characters WHERE user_id = ?').get(userId); }

function rollRarity(pool) {
  const available = RARITIES.filter(r => pool.includes(r.name));
  const total = available.reduce((s, r) => s + r.weight, 0);
  let roll = Math.random() * total;
  for (const r of available) { roll -= r.weight; if (roll <= 0) return r; }
  return available[0];
}

function rollItem(difficulty) {
  const pool = ITEM_POOLS[difficulty];
  const rarity = rollRarity(pool);
  const type = ['weapon','armor','trinket'][Math.floor(Math.random() * 3)];
  const name = ITEM_NAMES[type][Math.floor(Math.random() * ITEM_NAMES[type].length)];
  const statType = STAT_TYPES[Math.floor(Math.random() * STAT_TYPES.length)];
  const mult = { Common: 1, Uncommon: 1.5, Rare: 2.5, Epic: 4, Legendary: 7 };
  const statValue = Math.floor((Math.random() * 5 + 3) * mult[rarity.name]);
  return { item_name: name, rarity: rarity.name, stat_type: statType, stat_value: statValue, emoji: rarity.emoji };
}

function levelUpCheck(char) {
  let { level, xp } = char;
  const msgs = [];
  while (xp >= xpForLevel(level)) {
    xp -= xpForLevel(level);
    level++;
    msgs.push(`\n🎉 *LEVEL UP!* You are now Level *${level}*!`);
  }
  if (msgs.length > 0) db.prepare('UPDATE characters SET level=?, xp=? WHERE user_id=?').run(level, xp, char.user_id);
  return msgs.join('');
}

function formatTime(seconds) {
  if (seconds < 60) return `${seconds}s`;
  if (seconds < 3600) return `${Math.floor(seconds / 60)}m ${seconds % 60}s`;
  const h = Math.floor(seconds / 3600), m = Math.floor((seconds % 3600) / 60);
  return `${h}h ${m}m`;
}

function hpBar(current, max, length = 10) {
  const filled = Math.round((current / max) * length);
  return '█'.repeat(Math.max(0,filled)) + '░'.repeat(Math.max(0,length - filled));
}

function xpBar(xp, level, length = 10) {
  const needed = xpForLevel(level);
  const filled = Math.round((xp / needed) * length);
  return '▓'.repeat(Math.max(0,filled)) + '░'.repeat(Math.max(0,length - filled));
}

function calcPower(char) {
  return char.attack * 2 + char.defense + char.magic * 1.5 + char.speed + char.crit * 2 + char.level * 5;
}

function simulatePvP(attacker, defender) {
  // Turn-based simulation — highest power wins with some randomness
  let aHP = attacker.hp, dHP = defender.hp;
  let turn = 0;
  while (aHP > 0 && dHP > 0 && turn < 50) {
    // Attacker hits
    const aCrit = Math.random() * 100 < attacker.crit;
    const aDmg = Math.max(1, attacker.attack - Math.floor(defender.defense * 0.4) + Math.floor(Math.random() * 5));
    dHP -= aCrit ? aDmg * 2 : aDmg;
    if (dHP <= 0) break;
    // Defender hits back
    const dCrit = Math.random() * 100 < defender.crit;
    const dDmg = Math.max(1, defender.attack - Math.floor(attacker.defense * 0.4) + Math.floor(Math.random() * 5));
    aHP -= dCrit ? dDmg * 2 : dDmg;
    turn++;
  }
  return aHP > dHP ? 'attacker' : 'defender';
}

function getDailyQuests(char) {
  const today = new Date().toISOString().split('T')[0];
  if (char.daily_date === today && char.daily_quests) {
    return JSON.parse(char.daily_quests);
  }
  // Roll 3 random quests
  const shuffled = [...DAILY_QUESTS_POOL].sort(() => Math.random() - 0.5);
  const quests = shuffled.slice(0, 3).map(q => ({ ...q, progress: 0, done: false }));
  db.prepare('UPDATE characters SET daily_quests=?, daily_date=? WHERE user_id=?')
    .run(JSON.stringify(quests), today, char.user_id);
  return quests;
}

function progressQuest(userId, key, amount = 1) {
  const char = getChar(userId);
  if (!char) return;
  const today = new Date().toISOString().split('T')[0];
  if (char.daily_date !== today) { getDailyQuests(char); return; }
  const quests = JSON.parse(char.daily_quests || '[]');
  let changed = false;
  let magicEarned = 0;
  for (const q of quests) {
    if (q.key === key && !q.done) {
      q.progress = Math.min(q.target, (q.progress || 0) + amount);
      if (q.progress >= q.target) {
        q.done = true;
        magicEarned += q.reward;
        changed = true;
      }
    }
  }
  if (changed) {
    db.prepare('UPDATE characters SET daily_quests=?, magic_balance=magic_balance+? WHERE user_id=?')
      .run(JSON.stringify(quests), magicEarned, userId);
  } else {
    db.prepare('UPDATE characters SET daily_quests=? WHERE user_id=?').run(JSON.stringify(quests), userId);
  }
  return magicEarned;
}

// ─── INVENTORY HELPERS ───────────────────────────────────────────────────────
const ITEMS_PER_PAGE = 5;

function buildInventoryMessage(char, items, page) {
  const rarityOrder = { Legendary: 0, Epic: 1, Rare: 2, Uncommon: 3, Common: 4 };
  const sorted = [...items].sort((a, b) => rarityOrder[a.rarity] - rarityOrder[b.rarity]);
  const totalPages = Math.max(1, Math.ceil(sorted.length / ITEMS_PER_PAGE));
  const pageItems = sorted.slice(page * ITEMS_PER_PAGE, (page + 1) * ITEMS_PER_PAGE);
  const lines = pageItems.map(it => {
    const isEquipped = char.equipped == it.id;
    const onSale = it.for_sale ? ` 🏷️ *For Sale* (${it.price.toLocaleString()} $MAGIC)` : '';
    return `${it.emoji} *${it.item_name}* [${it.rarity}] Lv${it.level || 1}\n   📈 +${it.stat_value} ${it.stat_type}${isEquipped ? '  ✅ *Equipped*' : ''}${onSale}`;
  });
  return {
    text: `🎒 *Inventory* — ${items.length} items\nPage ${page + 1}/${totalPages}\n───────────────────\n` + (lines.join('\n\n') || '_Empty_'),
    pageItems, totalPages, page
  };
}

function buildInventoryKeyboard(char, pageItems, page, totalPages) {
  const rows = pageItems.map(it => {
    const isEquipped = char.equipped == it.id;
    return [Markup.button.callback(
      isEquipped ? `✅ ${it.item_name}` : `🧤 Equip: ${it.item_name}`,
      `inv_equip_${it.id}`
    )];
  });
  const actionRow = pageItems.map(it =>
    Markup.button.callback(`⬆️ Upgrade`, `inv_upgrade_${it.id}`)
  );
  if (actionRow.length) rows.push(actionRow.slice(0, 4));
  const navRow = [];
  if (page > 0) navRow.push(Markup.button.callback('◀️ Prev', `inv_page_${page - 1}`));
  if (page < totalPages - 1) navRow.push(Markup.button.callback('Next ▶️', `inv_page_${page + 1}`));
  if (navRow.length) rows.push(navRow);
  return Markup.inlineKeyboard(rows);
}


