// ─── /create ─────────────────────────────────────────────────────────────────
bot.command('create', async (ctx) => {
  if (getChar(ctx.from.id)) return ctx.replyWithMarkdown(`⚠️ You already have a hero! Use /profile.`);
  const buttons = Object.entries(CLASSES).map(([key, c]) =>
    [Markup.button.callback(`${c.emoji} ${c.label}`, `create_class_${key}`)]
  );
  await ctx.replyWithPhoto(
    { source: CLASS_IMAGES.warrior, filename: 'warrior.jpg' },
    {
      caption: `🌌 *Choose Your Class*\n\n` +
        Object.entries(CLASSES).map(([, c]) => `${c.emoji} *${c.label}* — ${c.desc}`).join('\n') +
        `\n\n_Your destiny awaits..._`,
      parse_mode: 'Markdown',
      reply_markup: Markup.inlineKeyboard(buttons).reply_markup
    }
  );
});

Object.keys(CLASSES).forEach(cls => {
  bot.action(`create_class_${cls}`, async (ctx) => {
    if (getChar(ctx.from.id)) return ctx.answerCbQuery('You already have a character!');
    const c = CLASSES[cls]; const s = c.stats;
    db.prepare(`INSERT INTO characters (user_id,username,class,level,xp,hp,max_hp,attack,defense,magic,speed,crit) VALUES (?,?,?,1,0,?,?,?,?,?,?,?)`)
      .run(ctx.from.id, ctx.from.username || ctx.from.first_name, cls, s.hp, s.max_hp, s.attack, s.defense, s.magic, s.speed, s.crit);
    await ctx.answerCbQuery(`${c.emoji} ${c.label} created!`);
    await ctx.editMessageCaption(
      `🌌 *Hero Forged!*\n\n${c.emoji} *${c.label}* — ${c.desc}\n\n` +
      `❤️ HP: ${s.hp}  ⚔️ ATK: ${s.attack}  🛡️ DEF: ${s.defense}\n` +
      `🔮 MAG: ${s.magic}  💨 SPD: ${s.speed}  🎯 CRIT: ${s.crit}%\n\n` +
      `_Your journey begins. Use /mission to embark!_`,
      undefined, { parse_mode: 'Markdown' }
    );
    await ctx.replyWithPhoto(
      { source: CLASS_IMAGES[cls] || CLASS_IMAGES.warrior, filename: 'class.jpg' },
      { caption: `${c.emoji} *Your ${c.label} awakens...*\n_The realm trembles._`, parse_mode: 'Markdown' }
    );
  });
});

// ─── /profile ────────────────────────────────────────────────────────────────
bot.command('profile', (ctx) => {
  const char = getChar(ctx.from.id);
  if (!char) return ctx.replyWithMarkdown(`❌ No hero. Use /create.`);
  const c = CLASSES[char.class];
  const equipped = char.equipped ? db.prepare('SELECT * FROM inventory WHERE id=?').get(char.equipped) : null;
  const guild = char.guild_id ? db.prepare('SELECT * FROM guilds WHERE id=?').get(char.guild_id) : null;
  const mission = db.prepare('SELECT * FROM missions WHERE user_id=? AND collected=0 ORDER BY id DESC LIMIT 1').get(ctx.from.id);
  let missionStatus = '🏕️ Resting';
  if (mission) {
    const endsAt = new Date(mission.ends_at).getTime() / 1000, now = Date.now() / 1000;
    missionStatus = now < endsAt
      ? `${MISSIONS[mission.difficulty].emoji} On Mission (${formatTime(Math.ceil(endsAt - now))} left)`
      : `✅ Mission Complete — /collect`;
  }
  ctx.replyWithMarkdown(
    `╔══════════════════════╗\n  🌌 *ASTRALIS HERO CARD*\n╚══════════════════════╝\n\n` +
    `${c.emoji} *${char.username || 'Hero'}* — ${c.label}${char.injured ? '  🩹 *INJURED*' : ''}\n` +
    `⭐ Level *${char.level}*  |  🆔 ${ctx.from.id}\n\n` +
    `❤️ HP  [${hpBar(char.hp, char.max_hp)}] ${char.hp}/${char.max_hp}\n` +
    `✨ XP  [${xpBar(char.xp, char.level)}] ${char.xp}/${xpForLevel(char.level)}\n\n` +
    `⚔️ ATK *${char.attack}*   🛡️ DEF *${char.defense}*\n` +
    `🔮 MAG *${char.magic}*   💨 SPD *${char.speed}*   🎯 CRIT *${char.crit}%*\n\n` +
    `🧤 Equipped: ${equipped ? `${equipped.emoji} ${equipped.item_name} Lv${equipped.level||1} (+${equipped.stat_value} ${equipped.stat_type})` : 'None'}\n` +
    `🏰 Guild: ${guild ? `*${guild.name}*` : 'None — /joinguild'}\n` +
    `⚔️ PvP: *${char.pvp_wins}W* / *${char.pvp_losses}L*\n` +
    `💰 Balance: *${(char.magic_balance||0).toLocaleString()} $MAGIC*\n` +
    `🗺️ Status: ${missionStatus}`
  );
});

// ─── /stats ───────────────────────────────────────────────────────────────────
bot.command('stats', (ctx) => {
  const char = getChar(ctx.from.id);
  if (!char) return ctx.replyWithMarkdown('❌ No hero. Use /create.');
  const c = CLASSES[char.class];
  const itemCount = db.prepare('SELECT COUNT(*) as c FROM inventory WHERE user_id=?').get(ctx.from.id).c;
  const missionCount = db.prepare('SELECT COUNT(*) as c FROM missions WHERE user_id=? AND collected=1').get(ctx.from.id).c;
  const burnCount = db.prepare('SELECT COUNT(*) as c FROM burns WHERE user_id=?').get(ctx.from.id).c;
  ctx.replyWithMarkdown(
    `📊 *${c.emoji} ${char.username} — Stats*\n\n` +
    `🎖️ Level *${char.level}* — ${char.xp}/${xpForLevel(char.level)} XP\n` +
    `⚡ Power Score: *${Math.floor(calcPower(char))}*\n\n` +
    `❤️ HP: ${char.hp}/${char.max_hp}\n⚔️ ATK: ${char.attack}\n🛡️ DEF: ${char.defense}\n` +
    `🔮 MAG: ${char.magic}\n💨 SPD: ${char.speed}\n🎯 CRIT: ${char.crit}%\n\n` +
    `📦 Items: ${itemCount}  |  🗺️ Missions: ${missionCount}\n` +
    `🔥 $MAGIC burned: ${(burnCount * MAGIC_BURN_AMOUNT).toLocaleString()}\n` +
    `⚔️ PvP: ${char.pvp_wins}W / ${char.pvp_losses}L`
  );
});

// ─── /balance ────────────────────────────────────────────────────────────────
bot.command('balance', (ctx) => {
  const char = getChar(ctx.from.id);
  if (!char) return ctx.replyWithMarkdown('❌ No hero. Use /create.');
  ctx.replyWithMarkdown(`💰 *Your $MAGIC Balance*\n\n*${(char.magic_balance||0).toLocaleString()} $MAGIC*\n\n_Earn more by completing missions, quests & winning PvP._`);
});

// ─── /mission ─────────────────────────────────────────────────────────────────
bot.command('mission', (ctx) => {
  const char = getChar(ctx.from.id);
  if (!char) return ctx.replyWithMarkdown('❌ No hero. Use /create.');
  if (char.injured) return ctx.replyWithMarkdown(`🩹 *You are injured!*\n\nUse /heal to recover (costs 50,000 $MAGIC).`);
  const active = db.prepare('SELECT * FROM missions WHERE user_id=? AND collected=0 ORDER BY id DESC LIMIT 1').get(ctx.from.id);
  if (active) {
    const endsAt = new Date(active.ends_at).getTime() / 1000, now = Date.now() / 1000;
    if (now < endsAt) return ctx.replyWithMarkdown(`⚠️ *Already on a mission!*\n\n⏳ Returns in: *${formatTime(Math.ceil(endsAt - now))}*\n\n_Use /collect once done._`);
    return ctx.replyWithMarkdown(`✅ Mission complete! Use /collect.`);
  }
  const buttons = Object.entries(MISSIONS).map(([key, m]) =>
    [Markup.button.callback(`${m.emoji} ${m.label} (${formatTime(m.duration)}) — ${m.xp[0]}-${m.xp[1]} XP`, `mission_start_${key}`)]
  );
  ctx.replyWithMarkdown(
    `🗺️ *Choose a Mission*\n\n` +
    Object.entries(MISSIONS).map(([,m]) => `${m.emoji} *${m.label}* — ${formatTime(m.duration)} | ${m.xp[0]}–${m.xp[1]} XP`).join('\n') +
    `\n\n🔥 All missions burn *100,000 $MAGIC*`,
    Markup.inlineKeyboard(buttons)
  );
});

Object.keys(MISSIONS).forEach(diff => {
  bot.action(`mission_start_${diff}`, (ctx) => {
    const char = getChar(ctx.from.id);
    if (!char) return ctx.answerCbQuery('No character!');
    if (char.injured) return ctx.answerCbQuery('You are injured! Use /heal first.');
    const active = db.prepare('SELECT * FROM missions WHERE user_id=? AND collected=0 ORDER BY id DESC LIMIT 1').get(ctx.from.id);
    if (active) return ctx.answerCbQuery('Already on a mission!');
    const m = MISSIONS[diff];
    const now = new Date(), endsAt = new Date(now.getTime() + m.duration * 1000);
    const result = db.prepare('INSERT INTO missions (user_id,difficulty,started_at,ends_at) VALUES (?,?,?,?)').run(ctx.from.id, diff, now.toISOString(), endsAt.toISOString());
    db.prepare('INSERT INTO burns (user_id,amount,mission_id) VALUES (?,?,?)').run(ctx.from.id, MAGIC_BURN_AMOUNT, result.lastInsertRowid);
    ctx.answerCbQuery(`${m.emoji} Mission started!`);
    ctx.editMessageText(
      `🌌 *Mission Started!*\n\n${m.emoji} *${m.label}*\n⏳ Duration: *${formatTime(m.duration)}*\n✨ XP: *${m.xp[0]}–${m.xp[1]}*\n🔥 Burned: *${MAGIC_BURN_AMOUNT.toLocaleString()} $MAGIC*\n\n_Use /collect when done._`,
      { parse_mode: 'Markdown' }
    );
  });
});

// ─── /collect ─────────────────────────────────────────────────────────────────
bot.command('collect', (ctx) => {
  const char = getChar(ctx.from.id);
  if (!char) return ctx.replyWithMarkdown('❌ No hero. Use /create.');
  const mission = db.prepare('SELECT * FROM missions WHERE user_id=? AND collected=0 ORDER BY id DESC LIMIT 1').get(ctx.from.id);
  if (!mission) return ctx.replyWithMarkdown('🏕️ No active mission. Use /mission!');
  const endsAt = new Date(mission.ends_at).getTime() / 1000, now = Date.now() / 1000;
  if (now < endsAt) return ctx.replyWithMarkdown(`⏳ Still in progress!\n\nReturns in: *${formatTime(Math.ceil(endsAt - now))}*`);
  const m = MISSIONS[mission.difficulty];
  const xpGained = Math.floor(Math.random() * (m.xp[1] - m.xp[0] + 1)) + m.xp[0];
  const magicEarned = Math.floor(m.burn * 0.1); // 10% cashback
  db.prepare('UPDATE characters SET xp=xp+?, magic_balance=magic_balance+? WHERE user_id=?').run(xpGained, magicEarned, ctx.from.id);
  const updatedChar = getChar(ctx.from.id);
  const lvlUpMsg = levelUpCheck(updatedChar);
  let itemMsg = '🎒 No item drop this time.';
  if (Math.random() < 0.7) {
    const item = rollItem(mission.difficulty);
    db.prepare('INSERT INTO inventory (user_id,item_name,rarity,stat_type,stat_value,emoji) VALUES (?,?,?,?,?,?)').run(ctx.from.id, item.item_name, item.rarity, item.stat_type, item.stat_value, item.emoji);
    itemMsg = `${item.emoji} *${item.rarity}* drop: *${item.item_name}* (+${item.stat_value} ${item.stat_type})`;
  }
  db.prepare('UPDATE missions SET collected=1 WHERE id=?').run(mission.id);
  // Quest progress
  progressQuest(ctx.from.id, 'complete_mission');
  if (['hard','epic'].includes(mission.difficulty)) progressQuest(ctx.from.id, 'complete_hard');
  const questBonus = getChar(ctx.from.id).magic_balance - updatedChar.magic_balance;
  ctx.replyWithMarkdown(
    `✅ *Mission Complete!*\n\n${m.emoji} *${m.label}* finished!\n\n` +
    `✨ XP: *+${xpGained}*\n💰 $MAGIC: *+${magicEarned.toLocaleString()}*\n` +
    `${itemMsg}${lvlUpMsg}\n\n` +
    `_Use /quests to check daily progress._`
  );
});

// ─── /heal ───────────────────────────────────────────────────────────────────
bot.command('heal', (ctx) => {
  const char = getChar(ctx.from.id);
  if (!char) return ctx.replyWithMarkdown('❌ No hero. Use /create.');
  if (!char.injured) return ctx.replyWithMarkdown(`✅ You are not injured!`);
  const cost = 50000;
  if ((char.magic_balance || 0) < cost) return ctx.replyWithMarkdown(`❌ Need *${cost.toLocaleString()} $MAGIC* to heal.\n\nYour balance: *${(char.magic_balance||0).toLocaleString()}*`);
  db.prepare('UPDATE characters SET injured=0, hp=max_hp, magic_balance=magic_balance-? WHERE user_id=?').run(cost, ctx.from.id);
  ctx.replyWithMarkdown(`💊 *Healed!*\n\nYou paid *${cost.toLocaleString()} $MAGIC* and are back to full health.\n\n_Use /mission to continue your adventure._`);
});


// ─── /arena (PvP) ─────────────────────────────────────────────────────────────
bot.command('arena', (ctx) => {
  const char = getChar(ctx.from.id);
  if (!char) return ctx.replyWithMarkdown('❌ No hero. Use /create.');
  if (char.injured) return ctx.replyWithMarkdown(`🩹 *Injured!* Use /heal first.`);
  // Find opponents (not self, not injured, has a character)
  const opponents = db.prepare(`SELECT * FROM characters WHERE user_id != ? AND injured = 0 ORDER BY RANDOM() LIMIT 3`).all(ctx.from.id);
  if (!opponents.length) return ctx.replyWithMarkdown(`⚔️ No opponents available right now. Try again later!`);
  const buttons = opponents.map(op => {
    const c = CLASSES[op.class];
    return [Markup.button.callback(`${c.emoji} ${op.username || 'Hero'} Lv${op.level} (Power: ${Math.floor(calcPower(op))})`, `pvp_challenge_${op.user_id}`)];
  });
  ctx.replyWithMarkdown(
    `⚔️ *PvP Arena*\n\n` +
    `Your Power: *${Math.floor(calcPower(char))}*\n\n` +
    `Choose your opponent:\n` +
    opponents.map(op => {
      const c = CLASSES[op.class];
      return `${c.emoji} *${op.username||'Hero'}* — Lv${op.level} ${c.label} (Power: ${Math.floor(calcPower(op))})`;
    }).join('\n') +
    `\n\n💰 Winner earns *50,000 $MAGIC*\n⚠️ Lose 3 in a row = injured`,
    Markup.inlineKeyboard(buttons)
  );
});

bot.action(/^pvp_challenge_(\d+)$/, (ctx) => {
  const defenderId = parseInt(ctx.match[1]);
  const attacker = getChar(ctx.from.id);
  const defender = getChar(defenderId);
  if (!attacker || !defender) return ctx.answerCbQuery('Player not found!');
  if (attacker.injured) return ctx.answerCbQuery('You are injured!');

  const result = simulatePvP(attacker, defender);
  const winnerId = result === 'attacker' ? ctx.from.id : defenderId;
  const loserId  = result === 'attacker' ? defenderId : ctx.from.id;
  const magicPrize = 50000;

  // Update winner
  db.prepare('UPDATE characters SET pvp_wins=pvp_wins+1, pvp_streak=pvp_streak+1, magic_balance=magic_balance+? WHERE user_id=?').run(magicPrize, winnerId);
  // Update loser
  const loser = getChar(loserId);
  const newStreak = loserId === ctx.from.id ? 0 : loser.pvp_streak; // reset streak on attacker loss
  const newLossStreak = (loser.pvp_losses + 1) % 3 === 0 ? 1 : 0; // injure every 3rd loss
  db.prepare('UPDATE characters SET pvp_losses=pvp_losses+1, pvp_streak=0, injured=? WHERE user_id=?').run(newLossStreak, loserId);

  // Log
  db.prepare('INSERT INTO pvp_log (attacker_id,defender_id,winner_id,magic_won) VALUES (?,?,?,?)').run(ctx.from.id, defenderId, winnerId, magicPrize);

  // Quest progress
  if (winnerId === ctx.from.id) {
    progressQuest(ctx.from.id, 'win_pvp');
    progressQuest(ctx.from.id, 'win_pvp_3');
  }

  const won = winnerId === ctx.from.id;
  const defenderChar = getChar(defenderId);
  const dc = CLASSES[defender.class];
  ctx.answerCbQuery(won ? '⚔️ You won!' : '💀 You lost!');
  ctx.editMessageText(
    `⚔️ *PvP Result*\n\n` +
    `${won ? '🏆 *VICTORY!*' : '💀 *DEFEAT!*'}\n\n` +
    `You vs ${dc.emoji} *${defender.username||'Hero'}*\n\n` +
    `${won
      ? `💰 You earned *+${magicPrize.toLocaleString()} $MAGIC*!`
      : `💀 You lost. ${newLossStreak ? '\n🩹 *You are now injured! Use /heal.*' : ''}`
    }\n\n` +
    `⚔️ Your record: *${getChar(ctx.from.id).pvp_wins}W / ${getChar(ctx.from.id).pvp_losses}L*`,
    { parse_mode: 'Markdown' }
  );
});

bot.command('pvpstats', (ctx) => {
  const char = getChar(ctx.from.id);
  if (!char) return ctx.replyWithMarkdown('❌ No hero. Use /create.');
  const recentFights = db.prepare(`SELECT * FROM pvp_log WHERE attacker_id=? OR defender_id=? ORDER BY fought_at DESC LIMIT 5`).all(ctx.from.id, ctx.from.id);
  const lines = recentFights.map(f => {
    const won = f.winner_id === ctx.from.id;
    return `${won ? '✅' : '❌'} vs ${f.attacker_id === ctx.from.id ? f.defender_id : f.attacker_id} — ${won ? `+${f.magic_won.toLocaleString()}` : 'loss'}`;
  });
  ctx.replyWithMarkdown(
    `⚔️ *PvP Stats*\n\n` +
    `🏆 Wins: *${char.pvp_wins}*  |  💀 Losses: *${char.pvp_losses}*\n\n` +
    `*Recent Fights:*\n${lines.join('\n') || '_No fights yet_'}`
  );
});


// ─── GUILD SYSTEM ─────────────────────────────────────────────────────────────
bot.command('createguild', (ctx) => {
  const char = getChar(ctx.from.id);
  if (!char) return ctx.replyWithMarkdown('❌ No hero. Use /create.');
  if (char.guild_id) return ctx.replyWithMarkdown('⚠️ You are already in a guild! Use /guild to view it.');
  const cost = 500000;
  if ((char.magic_balance||0) < cost) return ctx.replyWithMarkdown(`❌ Creating a guild costs *${cost.toLocaleString()} $MAGIC*.\n\nYour balance: *${(char.magic_balance||0).toLocaleString()}*`);
  const args = ctx.message.text.split(' ').slice(1).join(' ').trim();
  if (!args) return ctx.replyWithMarkdown(`Usage: /createguild [name]\nExample: /createguild Shadow Order\n\nCost: *${cost.toLocaleString()} $MAGIC*`);
  if (args.length > 30) return ctx.replyWithMarkdown('❌ Guild name too long (max 30 chars).');
  try {
    const result = db.prepare('INSERT INTO guilds (name, leader_id) VALUES (?, ?)').run(args, ctx.from.id);
    db.prepare('UPDATE characters SET guild_id=?, magic_balance=magic_balance-? WHERE user_id=?').run(result.lastInsertRowid, cost, ctx.from.id);
    ctx.replyWithMarkdown(`🏰 *Guild Created!*\n\n*${args}* is now founded!\nYou are the Guild Leader.\n\nShare this to recruit: /joinguild ${args}\n\n💰 *${cost.toLocaleString()} $MAGIC* spent.`);
  } catch(e) {
    ctx.replyWithMarkdown(`❌ Guild name "*${args}*" is already taken.`);
  }
});

bot.command('joinguild', (ctx) => {
  const char = getChar(ctx.from.id);
  if (!char) return ctx.replyWithMarkdown('❌ No hero. Use /create.');
  if (char.guild_id) return ctx.replyWithMarkdown('⚠️ Already in a guild! Use /guild to view or leave first.');
  const args = ctx.message.text.split(' ').slice(1).join(' ').trim();
  if (!args) return ctx.replyWithMarkdown('Usage: /joinguild [guild name]');
  const guild = db.prepare('SELECT * FROM guilds WHERE LOWER(name) = LOWER(?)').get(args);
  if (!guild) return ctx.replyWithMarkdown(`❌ Guild "*${args}*" not found.`);
  db.prepare('UPDATE characters SET guild_id=? WHERE user_id=?').run(guild.id, ctx.from.id);
  ctx.replyWithMarkdown(`🏰 *Joined ${guild.name}!*\n\nWelcome to the guild!\nUse /guild to see guild info.\nUse /raid to participate in boss raids!`);
});

bot.command('guild', (ctx) => {
  const char = getChar(ctx.from.id);
  if (!char) return ctx.replyWithMarkdown('❌ No hero. Use /create.');
  if (!char.guild_id) return ctx.replyWithMarkdown(`🏰 You're not in a guild.\n\nUse /joinguild [name] or /createguild [name] (costs 500,000 $MAGIC)`);
  const guild = db.prepare('SELECT * FROM guilds WHERE id=?').get(char.guild_id);
  if (!guild) return ctx.replyWithMarkdown('❌ Guild not found.');
  const members = db.prepare('SELECT * FROM characters WHERE guild_id=?').all(guild.id);
  const leader = members.find(m => m.user_id === guild.leader_id);
  const memberLines = members.slice(0,10).map((m,i) => {
    const c = CLASSES[m.class];
    return `${i+1}. ${c.emoji} *${m.username||'Hero'}* — Lv${m.level}`;
  });
  let raidStatus = '🏕️ No active raid';
  if (guild.raid_boss && guild.raid_hp > 0) {
    const raidEndsAt = guild.raid_ends_at ? new Date(guild.raid_ends_at).getTime()/1000 : 0;
    const now = Date.now()/1000;
    raidStatus = now < raidEndsAt
      ? `🐉 *${guild.raid_boss}* — ${hpBar(guild.raid_hp, guild.raid_max_hp)} ${guild.raid_hp}/${guild.raid_max_hp} HP`
      : `✅ Raid ended`;
  }
  ctx.replyWithMarkdown(
    `🏰 *${guild.name}*\n` +
    `👑 Leader: *${leader ? leader.username : 'Unknown'}*\n` +
    `👥 Members: *${members.length}*\n` +
    `⭐ Guild Level: *${guild.level}*\n\n` +
    `*Members:*\n${memberLines.join('\n')}\n\n` +
    `*Raid:* ${raidStatus}\n\n` +
    `Use /raid to start or join a boss raid!`
  );
});

bot.command('leaveguild', (ctx) => {
  const char = getChar(ctx.from.id);
  if (!char || !char.guild_id) return ctx.replyWithMarkdown('You are not in a guild.');
  const guild = db.prepare('SELECT * FROM guilds WHERE id=?').get(char.guild_id);
  if (guild && guild.leader_id === ctx.from.id) return ctx.replyWithMarkdown('❌ You are the guild leader. Transfer leadership first.');
  db.prepare('UPDATE characters SET guild_id=NULL WHERE user_id=?').run(ctx.from.id);
  ctx.replyWithMarkdown(`✅ You left *${guild?.name || 'the guild'}*.`);
});

// ─── RAID SYSTEM ──────────────────────────────────────────────────────────────
bot.command('raid', (ctx) => {
  const char = getChar(ctx.from.id);
  if (!char) return ctx.replyWithMarkdown('❌ No hero. Use /create.');
  if (!char.guild_id) return ctx.replyWithMarkdown('❌ Join a guild first! Use /joinguild.');
  const guild = db.prepare('SELECT * FROM guilds WHERE id=?').get(char.guild_id);
  // Active raid
  if (guild.raid_boss && guild.raid_hp > 0) {
    const raidEndsAt = new Date(guild.raid_ends_at).getTime()/1000, now = Date.now()/1000;
    if (now > raidEndsAt) {
      db.prepare('UPDATE guilds SET raid_boss=NULL, raid_hp=0 WHERE id=?').run(guild.id);
      return ctx.replyWithMarkdown(`💀 The raid ended! The boss escaped.\n\nStart a new one: /raid`);
    }
    // Attack the boss
    const dmg = Math.floor(calcPower(char) * (0.5 + Math.random() * 0.5));
    const newHp = Math.max(0, guild.raid_hp - dmg);
    db.prepare('UPDATE guilds SET raid_hp=? WHERE id=?').run(newHp, guild.id);
    progressQuest(ctx.from.id, 'raid_boss');
    if (newHp <= 0) {
      // Boss defeated — reward all guild members
      const boss = BOSS_POOL.find(b => b.name === guild.raid_boss);
      const members = db.prepare('SELECT * FROM characters WHERE guild_id=?').all(guild.id);
      members.forEach(m => {
        db.prepare('UPDATE characters SET xp=xp+?, magic_balance=magic_balance+? WHERE user_id=?').run(boss?.reward_xp||500, boss?.reward_magic||500000, m.user_id);
      });
      db.prepare('UPDATE guilds SET raid_boss=NULL, raid_hp=0, xp=xp+100 WHERE id=?').run(guild.id);
      return ctx.replyWithMarkdown(
        `🎉 *BOSS DEFEATED!*\n\n` +
        `${boss?.emoji||'💀'} *${guild.raid_boss}* has been slain!\n\n` +
        `All guild members received:\n` +
        `✨ *+${boss?.reward_xp||500} XP*\n` +
        `💰 *+${(boss?.reward_magic||500000).toLocaleString()} $MAGIC*`
      );
    }
    return ctx.replyWithMarkdown(
      `⚔️ *You hit the boss for ${dmg} damage!*\n\n` +
      `🐉 *${guild.raid_boss}*\n` +
      `${hpBar(newHp, guild.raid_max_hp)} ${newHp}/${guild.raid_max_hp} HP\n\n` +
      `_Keep attacking! Use /raid again._`
    );
  }
  // No active raid — check if leader wants to start one
  if (guild.leader_id !== ctx.from.id) return ctx.replyWithMarkdown(`🐉 No active raid.\n\nOnly the guild leader can start a raid. Ask them to use /startraid.`);
  const buttons = BOSS_POOL.map(b => [Markup.button.callback(`${b.emoji} ${b.name} (${b.hp} HP)`, `raid_start_${b.name.replace(/ /g,'_')}`)]);
  ctx.replyWithMarkdown(`🐉 *Start a Raid*\n\nChoose a boss to fight:`, Markup.inlineKeyboard(buttons));
});

BOSS_POOL.forEach(boss => {
  bot.action(`raid_start_${boss.name.replace(/ /g,'_')}`, (ctx) => {
    const char = getChar(ctx.from.id);
    if (!char?.guild_id) return ctx.answerCbQuery('No guild!');
    const guild = db.prepare('SELECT * FROM guilds WHERE id=?').get(char.guild_id);
    if (guild.leader_id !== ctx.from.id) return ctx.answerCbQuery('Only the leader can start raids!');
    const endsAt = new Date(Date.now() + 24 * 60 * 60 * 1000).toISOString();
    db.prepare('UPDATE guilds SET raid_boss=?, raid_hp=?, raid_max_hp=?, raid_ends_at=? WHERE id=?').run(boss.name, boss.hp, boss.hp, endsAt, guild.id);
    ctx.answerCbQuery(`${boss.emoji} Raid started!`);
    ctx.editMessageText(
      `🐉 *Raid Started!*\n\n${boss.emoji} *${boss.name}* has appeared!\n\n❤️ HP: *${boss.hp.toLocaleString()}*\n⏳ Expires in: *24 hours*\n\nAll guild members: use /raid to attack!`,
      { parse_mode: 'Markdown' }
    );
  });
});


// ─── MARKETPLACE ──────────────────────────────────────────────────────────────
bot.command('market', (ctx) => {
  const listings = db.prepare(`
    SELECT m.*, i.item_name, i.rarity, i.stat_type, i.stat_value, i.emoji, i.level,
           c.username as seller_name
    FROM market m
    JOIN inventory i ON m.item_id = i.id
    JOIN characters c ON m.seller_id = c.user_id
    ORDER BY m.listed_at DESC LIMIT 15
  `).all();
  if (!listings.length) return ctx.replyWithMarkdown(`🛒 *Marketplace*\n\n_No items for sale right now._\n\nList yours with /sell [item name] [price]`);
  const lines = listings.map((l,i) =>
    `${i+1}. ${l.emoji} *${l.item_name}* [${l.rarity}] Lv${l.level||1}\n   +${l.stat_value} ${l.stat_type} — *${l.price.toLocaleString()} $MAGIC* by ${l.seller_name}`
  );
  const buttons = listings.slice(0,5).map(l =>
    [Markup.button.callback(`Buy: ${l.item_name} (${l.price.toLocaleString()})`, `market_buy_${l.id}`)]
  );
  ctx.replyWithMarkdown(`🛒 *Marketplace* (${listings.length} listings)\n\n${lines.join('\n\n')}`, Markup.inlineKeyboard(buttons));
});

bot.command('sell', (ctx) => {
  const char = getChar(ctx.from.id);
  if (!char) return ctx.replyWithMarkdown('❌ No hero. Use /create.');
  const parts = ctx.message.text.split(' ').slice(1);
  const price = parseInt(parts[parts.length - 1]);
  const itemName = parts.slice(0, -1).join(' ').trim();
  if (!itemName || isNaN(price) || price < 1000) return ctx.replyWithMarkdown('Usage: /sell [item name] [price]\nExample: /sell Shadowblade 100000\n\nMinimum price: 1,000 $MAGIC');
  const items = db.prepare('SELECT * FROM inventory WHERE user_id=? AND for_sale=0').all(ctx.from.id);
  const item = items.find(it => it.item_name.toLowerCase().includes(itemName.toLowerCase()));
  if (!item) return ctx.replyWithMarkdown(`❌ Item not found or already listed.`);
  if (char.equipped == item.id) return ctx.replyWithMarkdown(`❌ Unequip the item first.`);
  db.prepare('UPDATE inventory SET for_sale=1, price=? WHERE id=?').run(price, item.id);
  db.prepare('INSERT INTO market (seller_id, item_id, price) VALUES (?,?,?)').run(ctx.from.id, item.id, price);
  progressQuest(ctx.from.id, 'sell_item');
  const fee = Math.floor(price * 0.05);
  ctx.replyWithMarkdown(`🏷️ *Listed!*\n\n${item.emoji} *${item.item_name}* [${item.rarity}]\nPrice: *${price.toLocaleString()} $MAGIC*\nFee on sale: *${fee.toLocaleString()} $MAGIC* (5%)\n\nView market: /market`);
});

bot.action(/^market_buy_(\d+)$/, (ctx) => {
  const listingId = parseInt(ctx.match[1]);
  const char = getChar(ctx.from.id);
  if (!char) return ctx.answerCbQuery('No character!');
  const listing = db.prepare('SELECT m.*, i.item_name, i.rarity, i.stat_type, i.stat_value, i.emoji, i.level FROM market m JOIN inventory i ON m.item_id=i.id WHERE m.id=?').get(listingId);
  if (!listing) return ctx.answerCbQuery('Listing not found!');
  if (listing.seller_id === ctx.from.id) return ctx.answerCbQuery("Can't buy your own item!");
  if ((char.magic_balance||0) < listing.price) return ctx.answerCbQuery(`Need ${listing.price.toLocaleString()} $MAGIC!`);
  const fee = Math.floor(listing.price * 0.05);
  const sellerEarns = listing.price - fee;
  // Transfer
  db.prepare('UPDATE inventory SET user_id=?, for_sale=0, price=0 WHERE id=?').run(ctx.from.id, listing.item_id);
  db.prepare('UPDATE characters SET magic_balance=magic_balance-? WHERE user_id=?').run(listing.price, ctx.from.id);
  db.prepare('UPDATE characters SET magic_balance=magic_balance+? WHERE user_id=?').run(sellerEarns, listing.seller_id);
  db.prepare('DELETE FROM market WHERE id=?').run(listingId);
  ctx.answerCbQuery(`✅ Purchased ${listing.item_name}!`);
  ctx.reply(`🛒 *Purchase Complete!*\n\n${listing.emoji} *${listing.item_name}* [${listing.rarity}]\nPaid: *${listing.price.toLocaleString()} $MAGIC*\n\nCheck /inventory to equip it!`, { parse_mode: 'Markdown' });
});

bot.command('cancelsale', (ctx) => {
  const char = getChar(ctx.from.id);
  if (!char) return ctx.replyWithMarkdown('❌ No hero.');
  const args = ctx.message.text.split(' ').slice(1).join(' ').trim();
  if (!args) return ctx.replyWithMarkdown('Usage: /cancelsale [item name]');
  const item = db.prepare('SELECT * FROM inventory WHERE user_id=? AND for_sale=1 AND LOWER(item_name) LIKE ?').get(ctx.from.id, `%${args.toLowerCase()}%`);
  if (!item) return ctx.replyWithMarkdown('❌ No listed item found with that name.');
  db.prepare('UPDATE inventory SET for_sale=0, price=0 WHERE id=?').run(item.id);
  db.prepare('DELETE FROM market WHERE item_id=?').run(item.id);
  ctx.replyWithMarkdown(`✅ *${item.item_name}* removed from market.`);
});


// ─── UPGRADE SYSTEM ───────────────────────────────────────────────────────────
bot.command('upgrade', (ctx) => {
  const char = getChar(ctx.from.id);
  if (!char) return ctx.replyWithMarkdown('❌ No hero. Use /create.');
  const args = ctx.message.text.split(' ').slice(1).join(' ').trim();
  if (!args) return ctx.replyWithMarkdown(
    `⬆️ *Upgrade System*\n\nUsage: /upgrade [item name]\n\n*Upgrade costs:*\n` +
    Object.entries(UPGRADE_COSTS).map(([r,c]) => `${r} → ${UPGRADE_NEXT[r]||'MAX'}: *${c.toLocaleString()} $MAGIC*`).join('\n') +
    `\n\nUpgrading increases item stat value by *+50%*!`
  );
  const item = db.prepare('SELECT * FROM inventory WHERE user_id=? AND LOWER(item_name) LIKE ?').get(ctx.from.id, `%${args.toLowerCase()}%`);
  if (!item) return ctx.replyWithMarkdown(`❌ Item not found. Use /inventory to see your items.`);
  if (item.rarity === 'Legendary') return ctx.replyWithMarkdown(`${item.emoji} *${item.item_name}* is already *Legendary* — max rarity!`);
  const cost = UPGRADE_COSTS[item.rarity];
  const nextRarity = UPGRADE_NEXT[item.rarity];
  if ((char.magic_balance||0) < cost) return ctx.replyWithMarkdown(`❌ Need *${cost.toLocaleString()} $MAGIC*\n\nYour balance: *${(char.magic_balance||0).toLocaleString()}*`);
  const nextRarityData = RARITIES.find(r => r.name === nextRarity);
  const newStatValue = Math.floor(item.stat_value * 1.5);
  const newLevel = (item.level||1) + 1;
  // Unequip if equipped, remove old stat bonus
  if (char.equipped == item.id) {
    if (STAT_TYPES.includes(item.stat_type)) {
      db.prepare(`UPDATE characters SET ${item.stat_type}=${item.stat_type}-? WHERE user_id=?`).run(item.stat_value, ctx.from.id);
    }
    db.prepare(`UPDATE characters SET ${item.stat_type}=${item.stat_type}+? WHERE user_id=?`).run(newStatValue, ctx.from.id);
  }
  db.prepare('UPDATE inventory SET rarity=?, emoji=?, stat_value=?, level=? WHERE id=?').run(nextRarity, nextRarityData.emoji, newStatValue, newLevel, item.id);
  db.prepare('UPDATE characters SET magic_balance=magic_balance-? WHERE user_id=?').run(cost, ctx.from.id);
  progressQuest(ctx.from.id, 'upgrade_item');
  ctx.replyWithMarkdown(
    `⬆️ *Item Upgraded!*\n\n` +
    `${nextRarityData.emoji} *${item.item_name}*\n` +
    `${item.rarity} → *${nextRarity}*\n` +
    `+${item.stat_value} → *+${newStatValue} ${item.stat_type}*\n\n` +
    `💰 Spent: *${cost.toLocaleString()} $MAGIC*`
  );
});

// ─── INVENTORY ────────────────────────────────────────────────────────────────
bot.command('inventory', (ctx) => {
  const char = getChar(ctx.from.id);
  if (!char) return ctx.replyWithMarkdown('❌ No hero. Use /create.');
  const items = db.prepare('SELECT * FROM inventory WHERE user_id=? ORDER BY obtained_at DESC').all(ctx.from.id);
  if (!items.length) return ctx.replyWithMarkdown('🎒 *Inventory empty!*\n\nComplete missions to earn items.');
  const { text, pageItems, totalPages, page } = buildInventoryMessage(char, items, 0);
  ctx.replyWithMarkdown(text, buildInventoryKeyboard(char, pageItems, page, totalPages));
});

bot.action(/^inv_page_(\d+)$/, (ctx) => {
  const page = parseInt(ctx.match[1]);
  const char = getChar(ctx.from.id);
  if (!char) return ctx.answerCbQuery('No character!');
  const items = db.prepare('SELECT * FROM inventory WHERE user_id=? ORDER BY obtained_at DESC').all(ctx.from.id);
  const { text, pageItems, totalPages } = buildInventoryMessage(char, items, page);
  ctx.editMessageText(text, { parse_mode: 'Markdown', ...buildInventoryKeyboard(char, pageItems, page, totalPages) });
  ctx.answerCbQuery();
});

bot.action(/^inv_equip_(\d+)$/, (ctx) => {
  const itemId = parseInt(ctx.match[1]);
  const char = getChar(ctx.from.id);
  if (!char) return ctx.answerCbQuery('No character!');
  const item = db.prepare('SELECT * FROM inventory WHERE id=? AND user_id=?').get(itemId, ctx.from.id);
  if (!item) return ctx.answerCbQuery('Item not found!');
  if (char.equipped == itemId) return ctx.answerCbQuery(`${item.emoji} Already equipped!`);
  if (char.equipped) {
    const old = db.prepare('SELECT * FROM inventory WHERE id=?').get(char.equipped);
    if (old && STAT_TYPES.includes(old.stat_type)) db.prepare(`UPDATE characters SET ${old.stat_type}=MAX(0,${old.stat_type}-?) WHERE user_id=?`).run(old.stat_value, ctx.from.id);
  }
  if (STAT_TYPES.includes(item.stat_type)) db.prepare(`UPDATE characters SET ${item.stat_type}=${item.stat_type}+? WHERE user_id=?`).run(item.stat_value, ctx.from.id);
  db.prepare('UPDATE characters SET equipped=? WHERE user_id=?').run(item.id, ctx.from.id);
  ctx.answerCbQuery(`${item.emoji} ${item.item_name} equipped! +${item.stat_value} ${item.stat_type}`);
  const updatedChar = getChar(ctx.from.id);
  const items = db.prepare('SELECT * FROM inventory WHERE user_id=? ORDER BY obtained_at DESC').all(ctx.from.id);
  let currentPage = 0;
  try { const m = ctx.callbackQuery.message.text.match(/Page (\d+)\//); if (m) currentPage = parseInt(m[1]) - 1; } catch(_) {}
  const { text, pageItems, totalPages } = buildInventoryMessage(updatedChar, items, currentPage);
  ctx.editMessageText(text, { parse_mode: 'Markdown', ...buildInventoryKeyboard(updatedChar, pageItems, currentPage, totalPages) });
});

bot.action(/^inv_upgrade_(\d+)$/, (ctx) => {
  const itemId = parseInt(ctx.match[1]);
  const char = getChar(ctx.from.id);
  if (!char) return ctx.answerCbQuery('No character!');
  const item = db.prepare('SELECT * FROM inventory WHERE id=? AND user_id=?').get(itemId, ctx.from.id);
  if (!item) return ctx.answerCbQuery('Item not found!');
  if (item.rarity === 'Legendary') return ctx.answerCbQuery('Already Legendary!');
  const cost = UPGRADE_COSTS[item.rarity];
  if ((char.magic_balance||0) < cost) return ctx.answerCbQuery(`Need ${cost.toLocaleString()} $MAGIC!`);
  const nextRarity = UPGRADE_NEXT[item.rarity];
  const nextRarityData = RARITIES.find(r => r.name === nextRarity);
  const newStatValue = Math.floor(item.stat_value * 1.5);
  if (char.equipped == item.id) {
    if (STAT_TYPES.includes(item.stat_type)) {
      db.prepare(`UPDATE characters SET ${item.stat_type}=${item.stat_type}-? WHERE user_id=?`).run(item.stat_value, ctx.from.id);
      db.prepare(`UPDATE characters SET ${item.stat_type}=${item.stat_type}+? WHERE user_id=?`).run(newStatValue, ctx.from.id);
    }
  }
  db.prepare('UPDATE inventory SET rarity=?, emoji=?, stat_value=?, level=? WHERE id=?').run(nextRarity, nextRarityData.emoji, newStatValue, (item.level||1)+1, item.id);
  db.prepare('UPDATE characters SET magic_balance=magic_balance-? WHERE user_id=?').run(cost, ctx.from.id);
  progressQuest(ctx.from.id, 'upgrade_item');
  ctx.answerCbQuery(`⬆️ Upgraded to ${nextRarity}!`);
  const updatedChar = getChar(ctx.from.id);
  const items = db.prepare('SELECT * FROM inventory WHERE user_id=? ORDER BY obtained_at DESC').all(ctx.from.id);
  let currentPage = 0;
  try { const m = ctx.callbackQuery.message.text.match(/Page (\d+)\//); if (m) currentPage = parseInt(m[1]) - 1; } catch(_) {}
  const { text, pageItems, totalPages } = buildInventoryMessage(updatedChar, items, currentPage);
  ctx.editMessageText(text, { parse_mode: 'Markdown', ...buildInventoryKeyboard(updatedChar, pageItems, currentPage, totalPages) });
});


// ─── DAILY QUESTS ─────────────────────────────────────────────────────────────
bot.command('quests', (ctx) => {
  const char = getChar(ctx.from.id);
  if (!char) return ctx.replyWithMarkdown('❌ No hero. Use /create.');
  const quests = getDailyQuests(char);
  const lines = quests.map(q => {
    const bar = q.target > 1 ? ` (${q.progress||0}/${q.target})` : '';
    return `${q.done ? '✅' : '🔲'} *${q.desc}*${bar}\n   💰 Reward: ${q.reward.toLocaleString()} $MAGIC`;
  });
  const earned = quests.filter(q => q.done).reduce((s,q) => s + q.reward, 0);
  ctx.replyWithMarkdown(
    `📋 *Daily Quests*\n_Resets at midnight_\n\n` +
    lines.join('\n\n') +
    `\n\n💰 Earned today: *${earned.toLocaleString()} $MAGIC*`
  );
});

// ─── LEADERBOARD ──────────────────────────────────────────────────────────────
bot.command('top', (ctx) => {
  const heroes = db.prepare('SELECT * FROM characters ORDER BY level DESC, xp DESC LIMIT 10').all();
  if (!heroes.length) return ctx.replyWithMarkdown('🏆 No heroes yet!');
  const medals = ['🥇','🥈','🥉'];
  const lines = heroes.map((h,i) => {
    const c = CLASSES[h.class];
    return `${medals[i]||`*${i+1}.*`} ${c.emoji} *${h.username||'Hero'}* — Lv*${h.level}* ${c.label} | ⚡${Math.floor(calcPower(h))} | ⚔️${h.pvp_wins}W`;
  });
  ctx.replyWithMarkdown(`🏆 *ASTRALIS Leaderboard*\n\n${lines.join('\n')}\n\n_Rise through the ranks, hero._`);
});

